-- Canonical DDL for naap.canonical_streaming_demand_hourly_store.
-- Source of truth: this file. The resolver and MVs write rows;
-- this declaration governs the physical schema.
-- Apply with scripts/apply-store-ddl.sh; drift is caught by
-- warehouse/tests/test_store_ddl_drift.sql.

CREATE TABLE IF NOT EXISTS naap.canonical_streaming_demand_hourly_store (`window_start` DateTime('UTC'), `org` LowCardinality(String), `gateway` String, `region` Nullable(String), `pipeline_id` String, `model_id` Nullable(String), `sessions_count` UInt64, `avg_output_fps` Float64, `output_fps_sum` Float64, `status_samples` UInt64, `total_minutes` Float64, `known_sessions_count` UInt64, `requested_sessions` UInt64 DEFAULT 0, `startup_success_sessions` UInt64 DEFAULT 0, `no_orch_sessions` UInt64 DEFAULT 0, `startup_excused_sessions` UInt64 DEFAULT 0, `startup_failed_sessions` UInt64 DEFAULT 0, `loading_only_sessions` UInt64 DEFAULT 0, `zero_output_fps_sessions` UInt64 DEFAULT 0, `effective_failed_sessions` UInt64 DEFAULT 0, `served_sessions` UInt64, `unserved_sessions` UInt64, `total_demand_sessions` UInt64, `startup_unexcused_sessions` UInt64, `confirmed_swapped_sessions` UInt64, `inferred_swap_sessions` UInt64, `total_swapped_sessions` UInt64, `sessions_ending_in_error` UInt64, `error_status_samples` UInt64, `health_signal_count` UInt64 DEFAULT 0, `health_expected_signal_count` UInt64 DEFAULT 0, `health_signal_coverage_ratio` Float64, `startup_success_rate` Float64, `excused_failure_rate` Float64 DEFAULT 0, `effective_success_rate` Float64, `ticket_face_value_eth` Float64, `refresh_run_id` String, `artifact_checksum` String DEFAULT '', `refreshed_at` DateTime64(3, 'UTC') DEFAULT now64()) ENGINE = MergeTree PARTITION BY (org, toYYYYMM(window_start)) ORDER BY (org, window_start, gateway, pipeline_id, ifNull(model_id, ''), refreshed_at) SETTINGS index_granularity = 8192;
